const ticket = $('Loop Over Items').item.json;
const apiResponse = $input.item.json;

const fallback = {
  urgency: 'Low',
  category: 'General Inquiry',
  summary: 'Classification failed — could not parse LLM response.',
  flag_for_review: false
};

const VALID_URGENCY = ['High', 'Medium', 'Low'];
const VALID_CATEGORY = ['Document Issue', 'Account Access', 'Billing', 'Fraud Concern', 'General Inquiry'];

function buildResult(classification) {
  return {
    json: {
      ticket_id: ticket.ticket_id || '',
      created_at: ticket.created_at || '',
      customer_name: ticket.customer_name || '',
      customer_email: ticket.customer_email || '',
      subject: ticket.subject || '',
      body: ticket.body || '',
      status: ticket.status || '',
      urgency: classification.urgency,
      category: classification.category,
      summary: classification.summary,
      flag_for_review: classification.flag_for_review
    }
  };
}

if (apiResponse.error) {
  return buildResult(fallback);
}

try {
  let raw = apiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '';
  raw = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
  const match = raw.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('No JSON object found');
  const parsed = JSON.parse(match[0]);
  const classification = {
    urgency: VALID_URGENCY.includes(parsed.urgency) ? parsed.urgency : 'Low',
    category: VALID_CATEGORY.includes(parsed.category) ? parsed.category : 'General Inquiry',
    summary: (parsed.summary || 'No summary provided.').substring(0, 200),
    flag_for_review: typeof parsed.flag_for_review === 'boolean'
      ? parsed.flag_for_review
      : String(parsed.flag_for_review).toLowerCase() === 'true'
  };
  return buildResult(classification);
} catch (e) {
  return buildResult(fallback);
}

const ticket = $input.item.json;
const textToCheck = `${ticket.subject || ''} ${ticket.body || ''}`.toLowerCase();

const fraudKeywords = [
  'forged', 'fake id', 'fake document', 'altered document', 'doctored', 'tampered',
  'stolen identity', 'identity theft', 'impersonat', 'unauthorized account',
  'someone else using', 'used without my permission', 'not mine',
  'identity mismatch', 'suspicious activity'
];

for (const keyword of fraudKeywords) {
  if (textToCheck.includes(keyword)) {
    ticket.category = 'Fraud Concern';
    ticket.flag_for_review = true;
    const highUrgency = ['stolen identity', 'identity theft', 'impersonat', 'unauthorized account', 'forged', 'fake id', 'tampered'];
    for (const indicator of highUrgency) {
      if (textToCheck.includes(indicator)) {
        ticket.urgency = 'High';
        break;
      }
    }
    break;
  }
}

return { json: ticket };

const ticket = $('Loop Over Items').item.json;
const item = $input.item.json;
const retryCount = (item._retry_count || 0) + 1;
const maxRetries = 3;

if (retryCount > maxRetries) {
  return {
    json: {
      ticket_id: ticket.ticket_id || '',
      created_at: ticket.created_at || '',
      customer_name: ticket.customer_name || '',
      customer_email: ticket.customer_email || '',
      subject: ticket.subject || '',
      body: ticket.body || '',
      status: ticket.status || '',
      _retry_count: retryCount,
      _give_up: true,
      urgency: 'Low',
      category: 'General Inquiry',
      summary: 'Classification failed after maximum retries.',
      flag_for_review: false
    }
  };
}

return {
  json: {
    ticket_id: ticket.ticket_id || '',
    created_at: ticket.created_at || '',
    customer_name: ticket.customer_name || '',
    customer_email: ticket.customer_email || '',
    subject: ticket.subject || '',
    body: ticket.body || '',
    status: ticket.status || '',
    _retry_count: retryCount,
    _give_up: false,
    _backoff_seconds: Math.pow(2, retryCount)
  }
};

const ticket = $('Loop Over Items').item.json;
return {
  json: {
    ticket_id: ticket.ticket_id || '',
    created_at: ticket.created_at || '',
    customer_name: ticket.customer_name || '',
    customer_email: ticket.customer_email || '',
    subject: ticket.subject || '',
    body: ticket.body || '',
    status: ticket.status || '',
    urgency: ticket.urgency || 'Low',
    category: ticket.category || 'General Inquiry',
    summary: ticket.summary || 'Ticket body is empty or unreadable.',
    flag_for_review: ticket.flag_for_review === true
  }
};

// CRITICAL: one loop-back per batch — do not connect Clean Up directly to Loop.
const items = $input.all();

return items.map((item) => {
  const j = { ...item.json };
  delete j._skip;
  delete j._retry_count;
  delete j._give_up;
  delete j._backoff_seconds;
  return { json: j };
});

function escapeCSV(value) {
  if (value === null || value === undefined) return '';
  const s = String(value);
  if (s.includes(',') || s.includes('"') || s.includes('\n') || s.includes('\r')) {
    return '"' + s.replace(/"/g, '""') + '"';
  }
  return s;
}

const items = $input.all();
const headers = [
  'ticket_id', 'created_at', 'customer_name', 'customer_email',
  'subject', 'body', 'status', 'urgency', 'category', 'summary', 'flag_for_review'
];

let csvContent = headers.join(',') + '\n';
for (const item of items) {
  const row = headers.map(h => escapeCSV(item.json[h]));
  csvContent += row.join(',') + '\n';
}

return [{
  json: {
    csvContent,
    ticketCount: items.length
  }
}];

const csvContent = $input.item.json.csvContent;
const ticketCount = $input.item.json.ticketCount;
const binaryData = Buffer.from(csvContent, 'utf-8');

return {
  json: {
    ticketCount,
    message: `CSV file generated with ${ticketCount} ticket(s)`
  },
  binary: {
    data: {
      data: binaryData.toString('base64'),
      mimeType: 'text/csv',
      fileName: 'classified_tickets.csv'
    }
  }
};
